diagram.d2:
direction: right
world: { label: "World state\nrosters · standings"; class: store }
perc: { label: "perception.ts\nevaluatePlayer (noised)"; class: actor }
ass: { label: "Role assessments\nGM · Coach · Owner · Player"; class: changed }
dec: { label: "Decisions\ntrades · firings · lineups" }
sim: { label: "sim layer\nexecutes the decision"; class: external }
world -> perc: read
perc -> ass: perceive
ass -> dec: decide
dec -> sim: emit

diagrams.d2:
direction: right
dis: { label: "Disruption\nstar injury · breakout\nmandate · blockbuster"; class: actor }
reg: { label: "handler registry\ngm/plan/handlers" }
delta: { label: "PlanDelta" }
plan: { label: "StrategicPlan\nCapBoard · OrgDepthChart\nPipelineMap · ProScoutingBoard"; class: changed }
replan: { label: "fireReplanTrigger\ncascade rebuild" }
dis -> reg: route
reg -> delta: compute
delta -> plan: applyDeltaInPlace
plan -> replan: trade / cap event
replan -> plan: rebuild

shape: sequence_diagram
trig: { label: "triggers"; class: actor }
gma: { label: "GM A" }
gmb: { label: "GM B" }
exec: { label: "trade-execution" }
trig -> gma: runWeeklyTradeCycle()
gma -> gmb: generateTradeProposal()
gmb -> gma: evaluateTrade() → accept
gma -> exec: executeAcceptedTrade()
exec -> gma: fireReplanTrigger()

direction: right
ass: { label: "computeCoachAssessment\nsystem-fit ratings"; class: actor }
lineup: { label: "buildLineup\n4 lines · 3 pairs · PP/PK · G"; class: changed }
scratch: { label: "recommendScratches" }
gm: { label: "GM approves"; class: external }
sim: { label: "sim (each game)"; class: external }
ass -> lineup
ass -> scratch
scratch -> gm: gate
lineup -> sim: deploy

direction: right
rec: { label: "record vs expected\n+ recent losses"; class: actor }
blame: { label: "evaluateOwnerBlame\nblameTarget" }
sat: { label: "satisfaction\nrolling · debounced" }
fire: { label: "shouldFireCoach / Gm"; class: changed }
exec: { label: "processMidSeasonFiring\n(in sim)"; class: external }
rec -> blame
blame -> sat
sat -> fire: monthly gate
fire -> exec: if fire

diagrams.mermaid:
flowchart LR
  rec["record vs expected + recent losses"] --> blame["evaluateOwnerBlame"]
  blame --> sat["satisfaction: rolling, debounced"]
  sat -->|monthly gate| fire["shouldFireCoach / Gm"]
  fire -->|if fire| exec["processMidSeasonFiring in sim"]
  classDef changed fill:#ffd43b,stroke:#f08c00,color:#1b1b1b,stroke-width:2px;
  classDef actor fill:#d0ebff,stroke:#4dabf7,color:#1b1b1b;
  classDef external fill:#f1f3f5,stroke:#adb5bd,color:#1b1b1b;
  class rec actor; class fire changed; class exec external;

